module RAM(
    input clk,
    input rst_n,
    input write_en,
    input write_addr,
    input write_data,
    input read_en,
    input read_addr,
    output read_data
);

reg [5:0] mem [0:7];
assign read_data = mem[read_addr];

always @(posedge clk, negedge rst_n) begin
    if (!rst_n) begin
        mem[0] <= 6'b000000;
        mem[1] <= 6'b000000;
        mem[2] <= 6'b000000;
        mem[3] <= 6'b000000;
        mem[4] <= 6'b000000;
        mem[5] <= 6'b000000;
        mem[6] <= 6'b000000;
        mem[7] <= 6'b000000;
    end
    else if (write_en) begin
        mem[write_addr] <= write_data;
    end
end

endmodule
